class EventPipeline:
    def __init__(self, broker: MessageBroker):
        self.broker = broker
        self.handlers: dict[str, list] = {}

    async def emit(self, event: str, payload: dict):
        for handler in self.handlers.get(event, []):
            await handler(payload)
